  contactName: string | null;
  channel: string;
  leadStatus: string | null;
}

const LEAD_COLORS: Record<string, string> = {
  new: "bg-cl-blue/10 text-cl-blue",
  contacted: "bg-yellow-500/10 text-yellow-400",
  interested: "bg-purple-500/10 text-purple-400",
  converted: "bg-cl-accent/10 text-cl-accent",
  lost: "bg-red-500/10 text-red-400",
};

async function apiFetch(url: string, opts?: RequestInit) {
  const r = await fetch(url, { credentials: "include", ...opts });
  if (!r.ok) throw new Error(await r.text());
  return r.json();
}

export default function BroadcastPage() {
  const { toast } = useToast();
  const [message, setMessage] = useState("");
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [filterStatus, setFilterStatus] = useState("all");
  const [search, setSearch] = useState("");
  const [sending, setSending] = useState(false);

  const { data, isLoading, error } = useQuery<{ contacts: Contact[] }>({
    queryKey: ["broadcast-contacts"],
    queryFn: () => apiFetch("/api/broadcast/contacts"),
  });

  const contacts = (data?.contacts ?? []).filter((c) => {
    const matchStatus = filterStatus === "all" || c.leadStatus === filterStatus;
    const matchSearch = !search || (c.contactName ?? "").toLowerCase().includes(search.toLowerCase()) || c.phoneNumber.includes(search);
    return matchStatus && matchSearch;
  });

  const sendBroadcast = useMutation({
    mutationFn: (body: object) =>
      apiFetch("/api/broadcast/send", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      }),
    onSuccess: (res) => {
      toast({ title: "Difusión enviada", description: `${res.sent ?? 0} mensajes enviados correctamente.` });
      setMessage("");
      setSelected(new Set());
      setSending(false);
    },
    onError: (e) => {
      toast({ title: "Error al enviar", description: (e as Error).message, variant: "destructive" });
      setSending(false);
    },
  });

  const isUpgrade = (error as Error)?.message?.includes("403") || (error as Error)?.message?.includes("plan");

  const toggleAll = () => {
    if (selected.size === contacts.length) setSelected(new Set());
    else setSelected(new Set(contacts.map((c) => c.id)));
  };

  const handleSend = () => {
    if (!message.trim() || selected.size === 0) return;
    if (!confirm(`¿Enviar a ${selected.size} contacto(s)?\n\n"${message.slice(0, 80)}${message.length > 80 ? "…" : ""}"`)) return;
    setSending(true);
    sendBroadcast.mutate({
      recipientIds: Array.from(selected),
      message,
    });
  };

  return (
    <section className="p-8 space-y-6">
      {isUpgrade ? (
        <div className="bg-navy-card border border-white/5 rounded-2xl p-12 text-center">
          <i className="ti ti-lock text-5xl text-white/10 block mb-4" />
          <p className="text-base font-bold text-white/60 mb-2">Disponible desde plan Starter</p>
          <p className="text-sm text-white/30 mb-6 max-w-md mx-auto">Enviá mensajes masivos a todos tus contactos de WhatsApp con límites según tu plan.</p>
          <a href="/dashboard" className="inline-block px-6 py-2.5 bg-cl-accent text-navy text-sm font-bold rounded-lg no-underline hover:bg-cl-accent/90 transition">
            Ver planes →
          </a>
        </div>
      ) : (
        <>
          <div className="grid grid-cols-3 gap-4">
            <div className="bg-navy-card border border-white/5 rounded-2xl p-5 flex items-center gap-4">
              <div className="w-12 h-12 bg-cl-accent/10 text-cl-accent rounded-xl flex items-center justify-center text-2xl flex-shrink-0">
                <i className="ti ti-users" />
              </div>
              <div>
                <p className="text-xs font-bold text-white/40 uppercase tracking-wider">Contactos WhatsApp</p>
                <p className="text-2xl font-extrabold text-white mt-0.5">{data?.contacts.length ?? 0}</p>
              </div>
            </div>
            <div className="bg-navy-card border border-white/5 rounded-2xl p-5 flex items-center gap-4">
              <div className="w-12 h-12 bg-cl-blue/10 text-cl-blue rounded-xl flex items-center justify-center text-2xl flex-shrink-0">
                <i className="ti ti-checkbox" />
              </div>
              <div>
                <p className="text-xs font-bold text-white/40 uppercase tracking-wider">Seleccionados</p>
                <p className="text-2xl font-extrabold text-white mt-0.5">{selected.size}</p>
              </div>
            </div>
            <div className="bg-navy-card border border-white/5 rounded-2xl p-5 flex items-center gap-4">
              <div className="w-12 h-12 bg-purple-500/10 text-purple-400 rounded-xl flex items-center justify-center text-2xl flex-shrink-0">
                <i className="ti ti-filter" />
              </div>
              <div>
                <p className="text-xs font-bold text-white/40 uppercase tracking-wider">Filtrados</p>
                <p className="text-2xl font-extrabold text-white mt-0.5">{contacts.length}</p>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-[1fr_360px] gap-6">
            <div className="bg-navy-card border border-white/5 rounded-2xl overflow-hidden">
              <div className="flex items-center gap-3 px-5 py-3 border-b border-white/5">
                <input
                  type="text"
                  placeholder="Buscar contacto..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="flex-1 bg-navy border border-white/10 rounded-lg px-3 py-1.5 text-sm text-white placeholder-white/30 focus:outline-none focus:border-cl-accent/50"
                />
                <select
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                  className="bg-navy border border-white/10 rounded-lg px-3 py-1.5 text-sm text-white focus:outline-none focus:border-cl-accent/50"
                >
                  <option value="all">Todos los estados</option>
                  <option value="new">Nuevo</option>
                  <option value="contacted">Contactado</option>
                  <option value="interested">Interesado</option>
                  <option value="converted">Convertido</option>
                  <option value="lost">Perdido</option>
                </select>
                <button
                  onClick={toggleAll}
                  className="px-3 py-1.5 text-xs font-semibold text-white/60 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition whitespace-nowrap"
                >
                  {selected.size === contacts.length && contacts.length > 0 ? "Deseleccionar todo" : "Seleccionar todo"}
                </button>
              </div>

              {isLoading ? (
                <div className="p-12 text-center text-white/40 text-sm">Cargando contactos...</div>
              ) : contacts.length === 0 ? (
                <div className="p-12 text-center">
                  <i className="ti ti-users-group text-4xl text-white/10 block mb-3" />
                  <p className="text-sm text-white/40">No hay contactos de WhatsApp todavía.</p>
                </div>
              ) : (
                <div className="divide-y divide-white/5 max-h-[500px] overflow-y-auto">
                  {contacts.map((c) => (
                    <label key={c.id} className={`flex items-center gap-4 px-5 py-3 cursor-pointer transition ${selected.has(c.id) ? "bg-cl-accent/5" : "hover:bg-white/2"}`}>
                      <input
                        type="checkbox"
                        checked={selected.has(c.id)}
                        onChange={(e) => {
                          const s = new Set(selected);
                          if (e.target.checked) s.add(c.id); else s.delete(c.id);
                          setSelected(s);
                        }}
                        className="w-4 h-4 accent-[#2dd8a0] flex-shrink-0"
                      />
                      <div className="w-8 h-8 bg-cl-accent/10 text-cl-accent rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0">
                        {(c.contactName ?? c.phoneNumber).charAt(0).toUpperCase()}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-semibold text-white truncate">{c.contactName ?? "Sin nombre"}</p>
                        <p className="text-[11px] text-white/50">{c.phoneNumber}</p>
                      </div>
                      {c.leadStatus && (
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${LEAD_COLORS[c.leadStatus] ?? "bg-white/5 text-white/40"}`}>
                          {c.leadStatus}
                        </span>
                      )}
                    </label>
                  ))}
                </div>
              )}
            </div>

            <div className="bg-navy-card border border-white/5 rounded-2xl p-6 flex flex-col gap-4">
              <div>
                <h3 className="text-sm font-bold text-white mb-0.5">Redactar mensaje</h3>
                <p className="text-[11px] text-white/40">Se enviará por WhatsApp a cada contacto seleccionado.</p>
              </div>
              <textarea
                className="w-full flex-1 bg-navy border border-white/10 rounded-xl px-4 py-3 text-sm text-white placeholder-white/30 focus:outline-none focus:border-cl-accent/50 resize-none min-h-[200px]"
                placeholder="Hola {nombre}, queríamos avisarte que…"
                value={message}
                onChange={(e) => setMessage(e.target.value)}
              />
              <div className="flex items-center justify-between text-[11px] text-white/40">
                <span>{message.length} caracteres</span>
                <span>{selected.size} destinatario(s)</span>
              </div>
              {message.includes("{nombre}") && (
                <div className="flex items-start gap-2 bg-cl-accent/5 border border-cl-accent/10 rounded-xl px-3 py-2.5">
                  <i className="ti ti-info-circle text-cl-accent mt-0.5 flex-shrink-0" />
                  <p className="text-[11px] text-white/60"><strong className="text-cl-accent">Variable detectada:</strong> {"{nombre}"} se reemplaza por el nombre del contacto al enviar.</p>
                </div>
              )}
              <button
                onClick={handleSend}
                disabled={!message.trim() || selected.size === 0 || sending}
                className="w-full py-3 bg-cl-accent text-navy text-sm font-bold rounded-xl hover:bg-cl-accent/90 transition disabled:opacity-40 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              >
                {sending
                  ? <><i className="ti ti-loader-2 animate-spin" /> Enviando...</>
                  : <><i className="ti ti-send" /> Enviar a {selected.size} contacto(s)</>
                }
              </button>
              <div className="bg-white/5 rounded-xl p-3 space-y-1.5">
                <p className="text-[10px] font-bold text-white/40 uppercase tracking-wider">Límites por plan</p>
                {[["Starter", "100 msgs/envío"], ["Pro", "300 msgs/envío"], ["Business", "500 msgs/envío"], ["Enterprise", "1.000 msgs/envío"]].map(([plan, limit]) => (
                  <div key={plan} className="flex justify-between text-[11px]">
                    <span className="text-white/50">{plan}</span>
                    <span className="text-white/70 font-semibold">{limit}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </>
      )}
    </section>
  );
}

import { Switch, Route, Router as WouterRouter } from "wouter";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import Home from "@/pages/Home";
import Dashboard from "@/pages/Dashboard";
import Catalogo from "@/pages/Catalogo";
import AuthPage from "@/pages/Auth";
import ResetPassword from "@/pages/ResetPassword";
import NotFound from "@/pages/not-found";
import { AppShell } from "@/components/AppShell";
import Overview from "@/pages/app/Overview";
import AgentPage from "@/pages/app/Agent";
import AnalyticsPage from "@/pages/app/Analytics";
import ChatSim from "@/pages/app/Chat";
import Knowledge from "@/pages/app/Knowledge";
import ServicesPage from "@/pages/app/Services";
import FlowsPage from "@/pages/app/Flows";
import AppointmentsPage from "@/pages/app/Appointments";
import OrdersPage from "@/pages/app/Orders";
import BroadcastPage from "@/pages/app/Broadcast";
import MockupsPage from "@/pages/app/Mockups";
import { ErrorBoundary } from "@/components/ErrorBoundary";

const queryClient = new QueryClient();

function AppRoute({ children }: { children: React.ReactNode }) {
  return <AppShell>{children}</AppShell>;
}

function AppRoutes() {
  return (
    <Switch>
      <Route path="/" component={Home} />
      <Route path="/auth" component={AuthPage} />
      <Route path="/dashboard" component={Dashboard} />
      <Route path="/catalogo/:token" component={Catalogo} />
      <Route path="/reset-password" component={ResetPassword} />

      <Route path="/app">
        {() => <AppRoute><Overview /></AppRoute>}
      </Route>
      <Route path="/app/agent">
        {() => <AppRoute><AgentPage /></AppRoute>}
      </Route>
      <Route path="/app/analytics">
        {() => <AppRoute><AnalyticsPage /></AppRoute>}
      </Route>
      <Route path="/app/chat">
        {() => <AppRoute><ChatSim /></AppRoute>}
      </Route>
      <Route path="/app/knowledge">
        {() => <AppRoute><Knowledge /></AppRoute>}
      </Route>
      <Route path="/app/services">
        {() => <AppRoute><ServicesPage /></AppRoute>}
      </Route>
      <Route path="/app/flows">
        {() => <AppRoute><FlowsPage /></AppRoute>}
      </Route>
      <Route path="/app/appointments">
        {() => <AppRoute><AppointmentsPage /></AppRoute>}
      </Route>
      <Route path="/app/orders">
        {() => <AppRoute><OrdersPage /></AppRoute>}
      </Route>
      <Route path="/app/broadcast">
        {() => <AppRoute><BroadcastPage /></AppRoute>}
      </Route>
      <Route path="/app/mockups">
        {() => <AppRoute><MockupsPage /></AppRoute>}
      </Route>

      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <QueryClientProvider client={queryClient}>
        <TooltipProvider>
          <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
            <ErrorBoundary>
              <AppRoutes />
            </ErrorBoundary>
          </WouterRouter>
          <Toaster />
        </TooltipProvider>
      </QueryClientProvider>
    </ErrorBoundary>
  );
}

export default App;

import type { ReactNode } from "react";
import { Link, useLocation } from "wouter";
import { useAuth } from "@workspace/replit-auth-web";

const consoleNav = [
  { to: "/app",             label: "Panel General",       icon: "ti-layout-dashboard" },
  { to: "/app/agent",       label: "Configurar Agente IA", icon: "ti-robot" },
  { to: "/app/analytics",   label: "Analytics de Leads",   icon: "ti-chart-area-line" },
  { to: "/app/chat",        label: "Chat & RAG Trace",     icon: "ti-messages" },
  { to: "/app/flows",       label: "Flows",                icon: "ti-git-branch" },
] as const;

const operationsNav = [
  { to: "/app/appointments", label: "Agenda de Turnos",   icon: "ti-calendar-event" },
  { to: "/app/orders",       label: "Pedidos",             icon: "ti-shopping-bag" },
  { to: "/app/broadcast",    label: "Difusión Masiva",     icon: "ti-speakerphone" },
] as const;

const adminNav = [
  { to: "/app/services",   label: "Mis Servicios",         icon: "ti-apps" },
  { to: "/app/knowledge",  label: "Base de Conocimiento",  icon: "ti-file-text" },
  { to: "/app/mockups",    label: "Diseños de Referencia", icon: "ti-template" },
  { to: "/dashboard",      label: "Planes & Facturación",  icon: "ti-gift" },
] as const;

const titles: Record<string, { title: string; subtitle: string }> = {
  "/app":               { title: "Panel de Control y Analíticas",        subtitle: "Monitoreo unificado de la suite de automatización Clientum" },
  "/app/agent":         { title: "Configurador de Agente IA",            subtitle: "Definí el perfil, catálogo y FAQs — simulá conversaciones en tiempo real" },
  "/app/analytics":     { title: "Analytics de Leads & Conversaciones",  subtitle: "Desempeño operativo, capturas de leads y métricas por rubro" },
  "/app/chat":          { title: "Simulador de Chat & Traza RAG",         subtitle: "Probá el bot y observá el razonamiento en tiempo real" },
  "/app/flows":         { title: "Flows de Conversación",                 subtitle: "Respuestas automáticas disparadas por palabras clave de tus clientes" },
  "/app/appointments":  { title: "Agenda de Turnos",                      subtitle: "Turnos gestionados por el bot vía WhatsApp" },
  "/app/orders":        { title: "Pedidos por WhatsApp",                  subtitle: "Pedidos creados y gestionados por el bot con actualizaciones automáticas" },
  "/app/broadcast":     { title: "Difusión Masiva",                       subtitle: "Enviá mensajes masivos a tus contactos de WhatsApp" },
  "/app/services":      { title: "Mis Servicios",                         subtitle: "Activá y gestioná cada servicio del stack Clientum para tu empresa" },
  "/app/knowledge":     { title: "Base de Conocimiento (RAG)",            subtitle: "Documentos indexados y datos corporativos de prioridad" },
  "/app/mockups":       { title: "Diseños de Referencia",                 subtitle: "Mockups y prototipos del producto — referencia visual de funcionalidades" },
};

export function AppShell({ children }: { children: ReactNode }) {
  const [pathname] = useLocation();
  const meta = titles[pathname] ?? titles["/app"];
  const { user } = useAuth();

  function handleSignOut() {
    window.location.href = "/api/auth/logout";
  }

  const displayName = user?.firstName
    ? `${user.firstName}${user.lastName ? " " + user.lastName : ""}`
    : user?.email ?? "Usuario";

  return (
    <div className="grid grid-cols-[280px_1fr] w-screen h-screen overflow-hidden bg-navy text-white">
      <aside className="bg-navy-2 border-r border-white/5 flex flex-col h-full py-6 select-none z-10 overflow-y-auto">
        <Link href="/" className="px-6 pb-6 border-b border-white/5 mb-4 flex items-center gap-3 no-underline flex-shrink-0">
          <div className="w-8 h-8 bg-cl-accent rounded-lg flex items-center justify-center text-navy font-extrabold shadow-[0_0_15px_rgba(45,216,160,0.3)]">
            C
          </div>
          <div className="text-lg font-extrabold tracking-tight text-white">
            Clientum<span className="text-cl-accent">AI</span>
          </div>
        </Link>

        <NavGroup label="Consola de Agente" items={consoleNav} currentPath={pathname} />
        <NavGroup label="Operaciones" items={operationsNav} currentPath={pathname} />
        <NavGroup label="Administración" items={adminNav} currentPath={pathname} />

        <div className="mt-auto px-4 pt-4 border-t border-white/5 space-y-3 flex-shrink-0">
          {user && (
            <div className="px-3 py-2 flex items-center gap-2">
              {user.profileImageUrl ? (
                <img src={user.profileImageUrl} alt={displayName} className="w-7 h-7 rounded-full object-cover" />
              ) : (
                <div className="w-7 h-7 bg-cl-accent/20 text-cl-accent rounded-full flex items-center justify-center text-xs font-bold">
                  {displayName.charAt(0).toUpperCase()}
                </div>
              )}
              <div className="flex-1 min-w-0">
                <p className="text-xs font-semibold text-white truncate">{displayName}</p>
                {user.email && <p className="text-[10px] text-white/40 truncate">{user.email}</p>}
              </div>
            </div>
          )}
          <button
            onClick={handleSignOut}
            className="w-full flex items-center gap-2 px-3 py-2 text-xs font-semibold text-white/60 hover:text-white hover:bg-white/5 rounded-lg transition-all"
          >
            <i className="ti ti-logout text-base" /> Cerrar sesión
          </button>
        </div>
      </aside>

      <main className="flex flex-col h-screen overflow-hidden">
        <header className="bg-navy border-b border-white/5 px-8 py-4 flex items-center justify-between flex-shrink-0">
          <div>
            <h1 className="text-xl font-bold text-white">{meta.title}</h1>
            <p className="text-xs text-white/50">{meta.subtitle}</p>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2 bg-cl-accent/10 border border-cl-accent/20 px-3 py-1.5 rounded-full text-xs font-semibold text-cl-accent">
              <i className="ti ti-bolt text-sm" />
              Demo activo
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto bg-navy-card2 relative">{children}</div>
      </main>
    </div>
  );
}

type NavItem = { to: string; label: string; icon: string };

function NavGroup({
  label,
  items,
  currentPath,
}: {
  label: string;
  items: readonly NavItem[];
  currentPath: string;
}) {
  return (
    <div className="px-3 mb-4">
      <div className="text-[10px] font-bold text-white/30 uppercase tracking-wider pl-3 mb-2">{label}</div>
      <nav className="space-y-0.5">
        {items.map((it) => {
          const isActive = it.to === "/app"
            ? currentPath === "/app"
            : currentPath.startsWith(it.to);
          return (
            <Link
              key={it.to}
              href={it.to}
              className={`flex items-center gap-3 w-full px-3 py-2 text-sm font-semibold rounded-lg transition-all no-underline ${
                isActive
                  ? "bg-cl-accent/10 text-cl-accent"
                  : "text-white/60 hover:text-white hover:bg-white/5"
              }`}
            >
              <i className={`ti ${it.icon} text-base`} /> {it.label}
            </Link>
          );
        })}
      </nav>
    </div>
  );
}

