    43→function renderMarkdown(text: string): string {
    44→  const lines = text.split("\n");
    45→  const out: string[] = [];
    46→  let inCode = false;
    47→  let inTable = false;
    48→
    49→  for (let i = 0; i < lines.length; i++) {
    50→    const line = lines[i];
