    89→
    90→    if (line.startsWith("# ")) {
    91→      out.push(`<h1 class="text-2xl font-extrabold text-white mt-6 mb-3">${inline(line.slice(2))}</h1>`);
    92→    } else if (line.startsWith("## ")) {
