    96→    } else if (line.startsWith("#### ")) {
    97→      out.push(`<h4 class="text-sm font-bold text-white/70 mt-4 mb-1">${inline(line.slice(5))}</h4>`);
    98→    } else if (line.startsWith("> ")) {
    99→      out.push(`<blockquote class="border-l-2 border-cl-accent/50 pl-4 my-3 text-sm text-white/60 italic">${inline(line.slice(2))}</blockquote>`);
   100→    } else if (/^- \[[xX]\]/.test(line)) {
   101→      out.push(`<div class="flex items-start gap-2 py-0.5"><span class="w-4 h-4 mt-0.5 flex-shrink-0 rounded bg-cl-accent/20 flex items-center justify-center text-cl-accent text-[10px]">✓</span><span class="text-sm text-white/50 line-through">${inline(line.replace(/^- \[[xX]\]\s*/, ""))}</span></div>`);
   102→    } else if (/^- \[ \]/.test(line)) {
   103→      out.push(`<div class="flex items-start gap-2 py-0.5"><span class="w-4 h-4 mt-0.5 flex-shrink-0 rounded border border-white/20"></span><span class="text-sm text-white/80">${inline(line.replace(/^- \[ \]\s*/, ""))}</span></div>`);
   104→    } else if (/^[-*] /.test(line)) {
   105→      out.push(`<div class="flex items-start gap-2 py-0.5 pl-1"><span class="w-1.5 h-1.5 mt-2 flex-shrink-0 rounded-full bg-cl-accent/50"></span><span class="text-sm text-white/80">${inline(line.replace(/^[-*] /, ""))}</span></div>`);
