import { useState, useEffect, useMemo } from "react";

type Priority = "🔴" | "🟠" | "🟡" | "🟢" | "none";

interface CheckItem {
  text: string;
  done: boolean;
  priority: Priority;
  indent: number;
}

interface Section {
  id: string;
  title: string;
  items: CheckItem[];
  done: number;
  total: number;
}

const PRIORITY_LABEL: Record<Priority, string> = {
  "🔴": "Bloqueante",
  "🟠": "Alta",
  "🟡": "Media",
  "🟢": "Nice-to-have",
  "none": "Completado",
};

const PRIORITY_CLASS: Record<Priority, string> = {
  "🔴": "text-red-400",
  "🟠": "text-orange-400",
  "🟡": "text-yellow-400",
  "🟢": "text-green-400",
  "none": "text-white/40",
};

function parsePriority(text: string): Priority {
  if (text.startsWith("🔴")) return "🔴";
  if (text.startsWith("🟠")) return "🟠";
  if (text.startsWith("🟡")) return "🟡";
  if (text.startsWith("🟢")) return "🟢";
  return "none";
}

function parseChecklist(md: string): Section[] {
  const lines = md.split("\n");
  const sections: Section[] = [];
  let current: Section | null = null;

  for (const line of lines) {
    const h2 = line.match(/^## (.+)/);
    if (h2) {
      if (current) sections.push(current);
      current = {
        id: h2[1].replace(/[^a-z0-9]+/gi, "-").toLowerCase(),
        title: h2[1],
        items: [],
        done: 0,
        total: 0,
      };
      continue;
    }

    const cbMatch = line.match(/^(\s*)-\s+\[([ xX])\]\s+(.*)/);
    if (cbMatch && current) {
      const indent = cbMatch[1].length;
      const done = cbMatch[2].toLowerCase() === "x";
      const text = cbMatch[3];
      const priority = parsePriority(text);
      current.items.push({ text, done, priority, indent });
      current.total++;
      if (done) current.done++;
    }
  }
  if (current) sections.push(current);
  return sections;
}

function inlineText(s: string): string {
  return s
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>")
    .replace(/`([^`]+)`/g, "<code class='check-code'>$1</code>")
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "<a href='$2' target='_blank' rel='noopener' class='check-link'>$1</a>");
}

export default function ChecklistPage() {
  const [raw, setRaw] = useState("");
  const [loading, setLoading] = useState(true);
  const [openSections, setOpenSections] = useState<Set<string>>(new Set());
  const [filterPriority, setFilterPriority] = useState<Priority | "all" | "pending">("all");
  const [search, setSearch] = useState("");

  useEffect(() => {
    fetch("/docs/CHECKLIST.md")
      .then(r => r.text())
      .then(t => {
        setRaw(t);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  const sections = useMemo(() => parseChecklist(raw), [raw]);

  const allDone = sections.reduce((a, s) => a + s.done, 0);
  const allTotal = sections.reduce((a, s) => a + s.total, 0);
  const pct = allTotal > 0 ? Math.round((allDone / allTotal) * 100) : 0;

  const toggleSection = (id: string) => {
    setOpenSections(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const expandAll = () => setOpenSections(new Set(sections.map(s => s.id)));
  const collapseAll = () => setOpenSections(new Set());

  function filteredItems(items: CheckItem[]): CheckItem[] {
    let out = items;
    if (filterPriority === "pending") out = out.filter(i => !i.done);
    else if (filterPriority !== "all") out = out.filter(i => i.priority === filterPriority && !i.done);
    if (search.trim()) {
      const q = search.toLowerCase();
      out = out.filter(i => i.text.toLowerCase().includes(q));
    }
    return out;
  }

  const PRIORITIES: (Priority | "all" | "pending")[] = ["all", "pending", "🔴", "🟠", "🟡", "🟢"];

  return (
    <div className="flex flex-col h-full overflow-hidden">
      <div className="flex-shrink-0 bg-navy border-b border-white/5 px-6 py-4">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-4">
            <div>
              <p className="text-xs text-white/40 mb-1">{allDone} / {allTotal} ítems completados</p>
              <div className="flex items-center gap-2">
                <div className="w-48 h-2 bg-white/5 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-cl-accent rounded-full transition-all duration-500"
                    style={{ width: `${pct}%` }}
                  />
                </div>
                <span className="text-xs font-bold text-cl-accent">{pct}%</span>
              </div>
            </div>
            <div className="flex gap-3 pl-4 border-l border-white/5">
              {(["🔴", "🟠", "🟡", "🟢"] as Priority[]).map(p => {
                const pending = sections.reduce((a, s) => a + s.items.filter(i => i.priority === p && !i.done).length, 0);
                return (
                  <div key={p} className="text-center">
                    <div className={`text-base leading-none`}>{p}</div>
                    <div className={`text-[10px] font-bold mt-0.5 ${PRIORITY_CLASS[p]}`}>{pending}</div>
                  </div>
                );
              })}
            </div>
          </div>
          <div className="flex items-center gap-2">
            <a
              href="/docs/CHECKLIST.md"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-white/50 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all no-underline"
            >
              <i className="ti ti-external-link text-sm" /> Ver archivo
            </a>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="relative flex-1 max-w-sm">
            <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-white/30 text-sm" />
            <input
              type="text"
              placeholder="Buscar en el checklist…"
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="w-full pl-8 pr-3 py-1.5 text-xs bg-white/5 border border-white/10 rounded-lg text-white placeholder:text-white/30 focus:outline-none focus:border-cl-accent/40"
            />
          </div>
          <div className="flex gap-1">
            {PRIORITIES.map(p => (
              <button
                key={p}
                onClick={() => setFilterPriority(p)}
                className={`px-2.5 py-1.5 text-xs font-semibold rounded-lg transition-all ${
                  filterPriority === p
                    ? "bg-cl-accent/20 text-cl-accent border border-cl-accent/30"
                    : "bg-white/5 text-white/50 hover:text-white hover:bg-white/10 border border-transparent"
                }`}
              >
                {p === "all" ? "Todos" : p === "pending" ? "Pendientes" : p}
              </button>
            ))}
          </div>
          <div className="flex gap-1 pl-2 border-l border-white/5">
            <button onClick={expandAll} className="px-2.5 py-1.5 text-xs text-white/40 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all">
              <i className="ti ti-unfold-more text-sm" />
            </button>
            <button onClick={collapseAll} className="px-2.5 py-1.5 text-xs text-white/40 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all">
              <i className="ti ti-fold text-sm" />
            </button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto px-6 py-4 space-y-2">
        {loading && (
          <div className="flex items-center gap-3 text-white/40 text-sm py-8">
            <i className="ti ti-loader-2 animate-spin text-xl" /> Cargando checklist…
          </div>
        )}

        {!loading && sections.map(section => {
          const items = filteredItems(section.items);
          if (!items.length && (search.trim() || filterPriority !== "all")) return null;
          const isOpen = openSections.has(section.id);
          const secDone = items.filter(i => i.done).length;
          const secTotal = items.length;
          const secPct = secTotal > 0 ? Math.round((secDone / secTotal) * 100) : 0;

          return (
            <div key={section.id} className="bg-navy rounded-xl border border-white/5 overflow-hidden">
              <button
                onClick={() => toggleSection(section.id)}
                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/3 transition-all text-left"
              >
                <div className="flex items-center gap-3">
                  <i className={`ti ${isOpen ? "ti-chevron-down" : "ti-chevron-right"} text-sm text-white/30`} />
                  <span className="text-sm font-bold text-white">{section.title}</span>
                  <span className="text-[10px] text-white/30">{section.done}/{section.total}</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="w-24 h-1.5 bg-white/5 rounded-full overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all ${secPct === 100 ? "bg-cl-accent" : "bg-cl-blue"}`}
                      style={{ width: `${secPct}%` }}
                    />
                  </div>
                  <span className={`text-[11px] font-bold w-8 text-right ${secPct === 100 ? "text-cl-accent" : "text-white/40"}`}>
                    {secPct}%
                  </span>
                </div>
              </button>

              {isOpen && (
                <div className="px-4 pb-3 space-y-0.5 border-t border-white/5 pt-2">
                  {(items.length > 0 ? items : section.items).map((item, idx) => (
                    <div
                      key={idx}
                      className={`flex items-start gap-2.5 py-1.5 px-2 rounded-lg group ${item.done ? "opacity-50" : ""}`}
                      style={item.indent > 0 ? { marginLeft: `${item.indent * 12}px` } : undefined}
                    >
                      <div className={`w-4 h-4 mt-0.5 flex-shrink-0 rounded border flex items-center justify-center transition-all ${
                        item.done
                          ? "bg-cl-accent/20 border-cl-accent/40 text-cl-accent"
                          : "border-white/20 group-hover:border-white/30"
                      }`}>
                        {item.done && <i className="ti ti-check text-[10px]" />}
                      </div>
                      <span
                        className={`text-xs leading-relaxed ${item.done ? "line-through text-white/30" : "text-white/80"}`}
                        dangerouslySetInnerHTML={{ __html: inlineText(item.text) }}
                      />
                      {!item.done && item.priority !== "none" && (
                        <span className={`ml-auto text-[10px] font-semibold flex-shrink-0 ${PRIORITY_CLASS[item.priority]}`}>
                          {item.priority}
                        </span>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

